def is_prime(num):
    if num <= 1:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

# Test the function with 17 and 24
results = {17: is_prime(17), 24: is_prime(24)}
results

